import{_ as e,a,b as d,c as o,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as l,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"إضافة قناة Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/dropbox.md","filePath":"ar-SA/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ar-SA/upload/dropbox.md"};function h(b,t,m,x,u,g){return l(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="إضافة-قناة-dropbox" tabindex="-1">إضافة قناة Dropbox <a class="header-anchor" href="#إضافة-قناة-dropbox" aria-label="Permalink to &quot;إضافة قناة Dropbox&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-أولًا؟" tabindex="-1">ما الذي تحتاجه أولًا؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-أولًا؟" aria-label="Permalink to &quot;ما الذي تحتاجه أولًا؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>لماذا تحتاجه</th></tr></thead><tbody><tr><td>حساب Dropbox</td><td>لتسجيل الدخول وتفويض التطبيق</td></tr><tr><td>Dropbox app</td><td>لإنشاء <code>App Key</code> و <code>App Secret</code></td></tr><tr><td>نطاق ImgBed الخاص بك</td><td>لاستخدامه في OAuth redirect URI</td></tr><tr><td>مساحة Dropbox متاحة</td><td>موقع التخزين الفعلي للملفات</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="الخطوة-1-أنشئ-dropbox-app" tabindex="-1">الخطوة 1: أنشئ Dropbox App <a class="header-anchor" href="#الخطوة-1-أنشئ-dropbox-app" aria-label="Permalink to &quot;الخطوة 1: أنشئ Dropbox App&quot;">​</a></h3><ol><li>افتح Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>أنشئ app جديدًا.</li><li>في access type اختر:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>أعطِ التطبيق اسمًا واضحًا، مثل <code>imgbed-app</code>.</li><li>افتح صفحة تفاصيل التطبيق بعد إنشائه.</li></ol><p>نوع الوصول الموصى به:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>التوصية</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>موصى به. يناسب طريقة ImgBed في تخزين الملفات.</td></tr><tr><td><code>Full Dropbox</code></td><td>غير موصى به. لا يحتاج ImgBed إلى الوصول إلى الحساب كاملًا.</td></tr></tbody></table><p><img src="'+e+'" alt="إنشاء Dropbox app" loading="lazy"></p><h3 id="الخطوة-2-أضف-redirect-uri" tabindex="-1">الخطوة 2: أضف Redirect URI <a class="header-anchor" href="#الخطوة-2-أضف-redirect-uri" aria-label="Permalink to &quot;الخطوة 2: أضف Redirect URI&quot;">​</a></h3><p>في صفحة تفاصيل Dropbox app، ابحث عن إعدادات OAuth أو Redirect URI وأضف:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>إذا كنت تستخدم لوحة الإدارة من أكثر من نطاق، فأضف كل callback URL مطابق.</p><p><img src="'+a+'" alt="ضبط redirect URI" loading="lazy"></p><h3 id="الخطوة-3-اضبط-app-permissions" tabindex="-1">الخطوة 3: اضبط App Permissions <a class="header-anchor" href="#الخطوة-3-اضبط-app-permissions" aria-label="Permalink to &quot;الخطوة 3: اضبط App Permissions&quot;">​</a></h3><p>افتح تبويب <code>Permissions</code> وفعّل على الأقل هذه scopes:</p><table tabindex="0"><thead><tr><th>Scope</th><th>مطلوب</th><th>الغرض</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>نعم</td><td>قراءة معلومات الحساب والحصة</td></tr><tr><td><code>files.metadata.read</code></td><td>نعم</td><td>قراءة metadata للملفات والمجلدات للتحقق من المسارات</td></tr><tr><td><code>files.metadata.write</code></td><td>نعم</td><td>إنشاء المجلدات وكتابة metadata</td></tr><tr><td><code>files.content.write</code></td><td>نعم</td><td>رفع الملفات. غياب هذا scope يسبب خطأ <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>موصى به</td><td>يسمح بالتنزيل والمعاينة والروابط المؤقتة للملفات</td></tr></tbody></table><p>بعد اختيار scopes اضغط <code>Submit</code> في أسفل الصفحة.</p><p><img src="'+d+'" alt="إضافة الصلاحيات" loading="lazy"></p><p>مهم:</p><table tabindex="0"><thead><tr><th>الحالة</th><th>ما العمل</th></tr></thead><tbody><tr><td>غيّرت scopes</td><td>شغّل مسار التفويض مرة أخرى واحصل على <code>Refresh Token</code> جديد.</td></tr><tr><td>لم تعِد التفويض</td><td>لن يحصل الرمز القديم على الصلاحيات الجديدة، وقد تستمر أخطاء الرفع.</td></tr></tbody></table><h3 id="الخطوة-4-انسخ-app-credentials" tabindex="-1">الخطوة 4: انسخ App Credentials <a class="header-anchor" href="#الخطوة-4-انسخ-app-credentials" aria-label="Permalink to &quot;الخطوة 4: انسخ App Credentials&quot;">​</a></h3><p>احفظ هاتين القيمتين من صفحة Dropbox app:</p><table tabindex="0"><thead><tr><th>حقل Dropbox</th><th>حقل ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="الخطوة-5-املأ-قناة-dropbox" tabindex="-1">الخطوة 5: املأ قناة Dropbox <a class="header-anchor" href="#الخطوة-5-املأ-قناة-dropbox" aria-label="Permalink to &quot;الخطوة 5: املأ قناة Dropbox&quot;">​</a></h3><p>في إعدادات الرفع اختر <code>Dropbox</code> واملأ:</p><table tabindex="0"><thead><tr><th>حقل ImgBed</th><th>ما الذي تدخله</th></tr></thead><tbody><tr><td>Channel name</td><td>اسم واضح، مثل <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>اتركه فارغًا الآن</td></tr><tr><td>Root directory</td><td>اختياري. الافتراضي <code>imgbed</code>.</td></tr><tr><td>Note</td><td>اختياري</td></tr></tbody></table><p><img src="'+o+'" alt="الحصول على token" loading="lazy"></p><h3 id="الخطوة-6-احصل-على-refresh-token" tabindex="-1">الخطوة 6: احصل على Refresh Token <a class="header-anchor" href="#الخطوة-6-احصل-على-refresh-token" aria-label="Permalink to &quot;الخطوة 6: احصل على Refresh Token&quot;">​</a></h3><ol><li>في ImgBed اضغط <code>Get Token</code>.</li><li>سجّل الدخول إلى حساب Dropbox الذي تريد ربطه.</li><li>وافق على طلب التفويض.</li><li>ستعرض صفحة callback قيمة <code>Refresh Token</code>.</li><li>انسخها.</li><li>ارجع إلى ImgBed والصقها في حقل <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="نسخ token" loading="lazy"></p><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الفحص</th><th>النتيجة المتوقعة</th></tr></thead><tbody><tr><td>بطاقة القناة</td><td>تظهر قناة Dropbox بعد الحفظ.</td></tr><tr><td>مفتاح القناة</td><td>يمكن تفعيل القناة.</td></tr><tr><td>حفظ الرمز</td><td>تعرض صفحة التفاصيل أن <code>Refresh Token</code> تم حفظه.</td></tr><tr><td>اختبار الرفع</td><td>تظهر صورة تجريبية داخل Dropbox app folder.</td></tr></tbody></table><p>إذا كانت quota limits مفعلة، اضغط استعلام الحصة. بعد نجاح الاستعلام تعرض بطاقة القناة المساحة المستخدمة والإجمالية ووقت آخر تحديث.</p><p><img src="'+p+`" alt="نجاح استعلام الحصة" loading="lazy"></p><h2 id="استكشاف-الأخطاء" tabindex="-1">استكشاف الأخطاء <a class="header-anchor" href="#استكشاف-الأخطاء" aria-label="Permalink to &quot;استكشاف الأخطاء&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المشكلة</th><th>الحل</th></tr></thead><tbody><tr><td>يقول ImgBed إن الإعداد غير مكتمل</td><td>تأكد من ملء <code>App Key</code> و <code>App Secret</code> و <code>Refresh Token</code>.</td></tr><tr><td>نجح التفويض لكن لا يظهر <code>Refresh Token</code></td><td>اضغط <code>Get Token</code> مرة أخرى وتأكد من استخدام offline authorization flow.</td></tr><tr><td>يفشل الرفع برسالة <code>required scope &#39;files.content.write&#39;</code></td><td>فعّل <code>files.content.write</code>، واضغط <code>Submit</code>، ثم احصل على <code>Refresh Token</code> جديد.</td></tr><tr><td>يفشل callback</td><td>تأكد أن redirect URI هو <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>لا يمكن العثور على الملفات</td><td>تأكد أن Dropbox app أُنشئ بوضع <code>App folder</code>.</td></tr></tbody></table><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح Dropbox App Console</span></span>
<span class="line"><span>-&gt; أنشئ app</span></span>
<span class="line"><span>-&gt; اختر App folder access</span></span>
<span class="line"><span>-&gt; أضف https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; فعّل account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; اختياريًا فعّل files.content.read</span></span>
<span class="line"><span>-&gt; اضغط Submit</span></span>
<span class="line"><span>-&gt; انسخ App Key و App Secret</span></span>
<span class="line"><span>-&gt; أدخلهما في ImgBed</span></span>
<span class="line"><span>-&gt; اضغط Get Token</span></span>
<span class="line"><span>-&gt; انسخ Refresh Token من صفحة callback</span></span>
<span class="line"><span>-&gt; الصقه في ImgBed واحفظ</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const _=s(c,[["render",h]]);export{y as __pageData,_ as default};
